"use strict";(globalThis.webpackChunklearn_design_patterns_docs=globalThis.webpackChunklearn_design_patterns_docs||[]).push([[2067],{22207(n,t,e){e.r(t),e.d(t,{assets:()=>l,contentTitle:()=>d,default:()=>u,frontMatter:()=>c,metadata:()=>o,toc:()=>a});const o=JSON.parse('{"id":"object-performance/singleton/code","title":"\u6e90\u4ee3\u7801","description":"Singleton \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801","source":"@site/docs/04-object-performance/singleton/code.md","sourceDirName":"04-object-performance/singleton","slug":"/object-performance/singleton/code","permalink":"/LearnDesignPatterns/docs/object-performance/singleton/code","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"title":"\u6e90\u4ee3\u7801","description":"Singleton \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},"sidebar":"docs","previous":{"title":"\u5355\u4f8b\u6a21\u5f0f\uff08Singleton\uff09","permalink":"/LearnDesignPatterns/docs/object-performance/singleton/"},"next":{"title":"\u4eab\u5143\u6a21\u5f0f\uff08Flyweight\uff09","permalink":"/LearnDesignPatterns/docs/object-performance/flyweight/"}}');var s=e(74848),i=e(28453);const c={sidebar_position:2,title:"\u6e90\u4ee3\u7801",description:"Singleton \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},d="\u6e90\u4ee3\u7801",l={},a=[{value:"\u5934\u6587\u4ef6\uff08Singleton.h\uff09",id:"\u5934\u6587\u4ef6singletonh",level:2},{value:"\u5b9e\u73b0\u6587\u4ef6\uff08Singleton.cpp\uff09",id:"\u5b9e\u73b0\u6587\u4ef6singletoncpp",level:2},{value:"\u6784\u5efa\u65b9\u5f0f",id:"\u6784\u5efa\u65b9\u5f0f",level:2}];function r(n){const t={admonition:"admonition",code:"code",h1:"h1",h2:"h2",header:"header",pre:"pre",...(0,i.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"\u6e90\u4ee3\u7801",children:"\u6e90\u4ee3\u7801"})}),"\n",(0,s.jsx)(t.h2,{id:"\u5934\u6587\u4ef6singletonh",children:"\u5934\u6587\u4ef6\uff08Singleton.h\uff09"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="Singleton.h" showLineNumbers',children:"#pragma once\n\n#include <string>\n#include <unordered_map>\n#include <mutex>\n#include <memory>\n#include <vector>\n#include <iostream>\n\n// ============================================================\n// Singleton \u6a21\u5f0f \u2014\u2014 \u5e94\u7528\u914d\u7f6e\u7ba1\u7406\u5668 & \u6570\u636e\u5e93\u8fde\u63a5\u6c60\n// \u786e\u4fdd\u4e00\u4e2a\u7c7b\u4ec5\u6709\u4e00\u4e2a\u5b9e\u4f8b\uff0c\u5e76\u63d0\u4f9b\u5168\u5c40\u8bbf\u95ee\u70b9\n// ============================================================\n\n// ---------- \u573a\u666f 1\uff1a\u5e94\u7528\u914d\u7f6e\u7ba1\u7406\u5668 ----------\n// \u4f7f\u7528 Meyers' Singleton \u2014\u2014 \u5229\u7528 C++11 \u9759\u6001\u5c40\u90e8\u53d8\u91cf\u7684\u7ebf\u7a0b\u5b89\u5168\u4fdd\u8bc1\nclass AppConfig {\npublic:\n    // \u83b7\u53d6\u552f\u4e00\u5b9e\u4f8b\uff08Meyers' Singleton\uff09\n    // C++11 \u6807\u51c6\u4fdd\u8bc1\uff1a\u5c40\u90e8\u9759\u6001\u53d8\u91cf\u7684\u521d\u59cb\u5316\u662f\u7ebf\u7a0b\u5b89\u5168\u7684\n    static AppConfig& getInstance();\n\n    // \u7981\u6b62\u62f7\u8d1d\u548c\u79fb\u52a8\uff0c\u9632\u6b62\u4ea7\u751f\u7b2c\u4e8c\u4e2a\u5b9e\u4f8b\n    AppConfig(const AppConfig&) = delete;\n    AppConfig& operator=(const AppConfig&) = delete;\n    AppConfig(AppConfig&&) = delete;\n    AppConfig& operator=(AppConfig&&) = delete;\n\n    // \u914d\u7f6e\u8bfb\u5199\u63a5\u53e3\n    void set(const std::string& key, const std::string& value);\n    std::string get(const std::string& key, const std::string& defaultValue = \"\") const;\n    bool contains(const std::string& key) const;\n    void loadFromDefaults();\n    void printAll() const;\n\nprivate:\n    // \u6784\u9020\u51fd\u6570\u79c1\u6709\u5316 \u2014\u2014 Singleton \u7684\u6838\u5fc3\u7ea6\u675f\n    AppConfig();\n    ~AppConfig() = default;\n\n    // \u4f7f\u7528 mutable mutex \u5141\u8bb8\u5728 const \u65b9\u6cd5\u4e2d\u52a0\u9501\n    mutable std::mutex mutex_;\n    std::unordered_map<std::string, std::string> config_;\n};\n\n\n// ---------- \u573a\u666f 2\uff1a\u6570\u636e\u5e93\u8fde\u63a5\u6c60 ----------\n// \u6a21\u62df\u6570\u636e\u5e93\u8fde\u63a5\nclass DatabaseConnection {\npublic:\n    explicit DatabaseConnection(int id, const std::string& connStr);\n    ~DatabaseConnection();\n\n    int getId() const { return id_; }\n    bool isInUse() const { return inUse_; }\n    void setInUse(bool inUse) { inUse_ = inUse; }\n    void execute(const std::string& sql);\n\nprivate:\n    int id_;\n    std::string connectionString_;\n    bool inUse_ = false;\n};\n\n// \u6570\u636e\u5e93\u8fde\u63a5\u6c60 \u2014\u2014 Singleton + \u5bf9\u8c61\u6c60\n// \u5168\u5c40\u53ea\u6709\u4e00\u4e2a\u8fde\u63a5\u6c60\u5b9e\u4f8b\uff0c\u7ba1\u7406\u6709\u9650\u6570\u91cf\u7684\u6570\u636e\u5e93\u8fde\u63a5\nclass ConnectionPool {\npublic:\n    static ConnectionPool& getInstance();\n\n    ConnectionPool(const ConnectionPool&) = delete;\n    ConnectionPool& operator=(const ConnectionPool&) = delete;\n\n    // \u83b7\u53d6\u4e00\u4e2a\u7a7a\u95f2\u8fde\u63a5\n    DatabaseConnection* acquire();\n    // \u5f52\u8fd8\u8fde\u63a5\n    void release(DatabaseConnection* conn);\n    // \u67e5\u770b\u8fde\u63a5\u6c60\u72b6\u6001\n    void printStatus() const;\n    size_t poolSize() const;\n    size_t activeCount() const;\n\nprivate:\n    ConnectionPool();\n    ~ConnectionPool() = default;\n\n    static constexpr size_t MAX_CONNECTIONS = 5;\n    mutable std::mutex mutex_;\n    std::vector<std::unique_ptr<DatabaseConnection>> connections_;\n};\n"})}),"\n",(0,s.jsx)(t.h2,{id:"\u5b9e\u73b0\u6587\u4ef6singletoncpp",children:"\u5b9e\u73b0\u6587\u4ef6\uff08Singleton.cpp\uff09"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="Singleton.cpp" showLineNumbers',children:'#include "Singleton.h"\n#include <thread>\n#include <sstream>\n#include <algorithm>\n\n// ============================================================\n// AppConfig \u5b9e\u73b0\n// ============================================================\n\nAppConfig& AppConfig::getInstance() {\n    // Meyers\' Singleton\uff1aC++11 \u4fdd\u8bc1\u5c40\u90e8\u9759\u6001\u53d8\u91cf\u521d\u59cb\u5316\u7684\u7ebf\u7a0b\u5b89\u5168\u6027\n    // \u7f16\u8bd1\u5668\u4f1a\u81ea\u52a8\u5728\u5e95\u5c42\u63d2\u5165\u53cc\u68c0\u9501\uff0c\u65e0\u9700\u624b\u52a8\u5b9e\u73b0\n    static AppConfig instance;\n    return instance;\n}\n\nAppConfig::AppConfig() {\n    std::cout << "[AppConfig] \u914d\u7f6e\u7ba1\u7406\u5668\u521d\u59cb\u5316\uff08\u4ec5\u6267\u884c\u4e00\u6b21\uff09" << std::endl;\n}\n\nvoid AppConfig::set(const std::string& key, const std::string& value) {\n    std::lock_guard<std::mutex> lock(mutex_);\n    config_[key] = value;\n}\n\nstd::string AppConfig::get(const std::string& key, const std::string& defaultValue) const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    auto it = config_.find(key);\n    return (it != config_.end()) ? it->second : defaultValue;\n}\n\nbool AppConfig::contains(const std::string& key) const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    return config_.find(key) != config_.end();\n}\n\nvoid AppConfig::loadFromDefaults() {\n    std::lock_guard<std::mutex> lock(mutex_);\n    // \u6a21\u62df\u4ece\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u9ed8\u8ba4\u914d\u7f6e\n    config_["app.name"] = "DesignPatternDemo";\n    config_["app.version"] = "1.0.0";\n    config_["db.host"] = "localhost";\n    config_["db.port"] = "5432";\n    config_["db.name"] = "pattern_db";\n    config_["db.max_connections"] = "5";\n    config_["log.level"] = "INFO";\n    config_["log.file"] = "/var/log/app.log";\n    std::cout << "[AppConfig] \u5df2\u52a0\u8f7d " << config_.size() << " \u9879\u9ed8\u8ba4\u914d\u7f6e" << std::endl;\n}\n\nvoid AppConfig::printAll() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    std::cout << "[AppConfig] \u5f53\u524d\u914d\u7f6e\u9879 (" << config_.size() << " \u9879):" << std::endl;\n    for (const auto& [key, value] : config_) {\n        std::cout << "  " << key << " = " << value << std::endl;\n    }\n}\n\n// ============================================================\n// DatabaseConnection \u5b9e\u73b0\n// ============================================================\n\nDatabaseConnection::DatabaseConnection(int id, const std::string& connStr)\n    : id_(id), connectionString_(connStr) {\n    std::cout << "  [Connection #" << id_ << "] \u5df2\u521b\u5efa\uff0c\u8fde\u63a5\u5230: " << connStr << std::endl;\n}\n\nDatabaseConnection::~DatabaseConnection() {\n    std::cout << "  [Connection #" << id_ << "] \u5df2\u65ad\u5f00" << std::endl;\n}\n\nvoid DatabaseConnection::execute(const std::string& sql) {\n    std::cout << "  [Connection #" << id_ << "] \u6267\u884c SQL: " << sql << std::endl;\n}\n\n// ============================================================\n// ConnectionPool \u5b9e\u73b0\n// ============================================================\n\nConnectionPool& ConnectionPool::getInstance() {\n    static ConnectionPool instance;\n    return instance;\n}\n\nConnectionPool::ConnectionPool() {\n    std::cout << "[ConnectionPool] \u521d\u59cb\u5316\u8fde\u63a5\u6c60\uff08\u5bb9\u91cf: "\n              << MAX_CONNECTIONS << "\uff09" << std::endl;\n\n    // \u4ece\u914d\u7f6e\u7ba1\u7406\u5668\u8bfb\u53d6\u8fde\u63a5\u4fe1\u606f \u2014\u2014 \u4f53\u73b0\u4e24\u4e2a Singleton \u4e4b\u95f4\u7684\u534f\u4f5c\n    auto& config = AppConfig::getInstance();\n    std::string host = config.get("db.host", "localhost");\n    std::string port = config.get("db.port", "5432");\n    std::string dbName = config.get("db.name", "default_db");\n    std::string connStr = host + ":" + port + "/" + dbName;\n\n    // \u9884\u521b\u5efa\u8fde\u63a5\n    for (size_t i = 0; i < MAX_CONNECTIONS; ++i) {\n        connections_.push_back(\n            std::make_unique<DatabaseConnection>(static_cast<int>(i + 1), connStr)\n        );\n    }\n}\n\nDatabaseConnection* ConnectionPool::acquire() {\n    std::lock_guard<std::mutex> lock(mutex_);\n    for (auto& conn : connections_) {\n        if (!conn->isInUse()) {\n            conn->setInUse(true);\n            std::cout << "[ConnectionPool] \u5206\u914d\u8fde\u63a5 #" << conn->getId() << std::endl;\n            return conn.get();\n        }\n    }\n    std::cout << "[ConnectionPool] \u8b66\u544a\uff1a\u65e0\u7a7a\u95f2\u8fde\u63a5\uff01" << std::endl;\n    return nullptr;\n}\n\nvoid ConnectionPool::release(DatabaseConnection* conn) {\n    if (!conn) return;\n    std::lock_guard<std::mutex> lock(mutex_);\n    conn->setInUse(false);\n    std::cout << "[ConnectionPool] \u5f52\u8fd8\u8fde\u63a5 #" << conn->getId() << std::endl;\n}\n\nvoid ConnectionPool::printStatus() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    size_t active = std::count_if(connections_.begin(), connections_.end(),\n        [](const auto& c) { return c->isInUse(); });\n    std::cout << "[ConnectionPool] \u72b6\u6001: " << active << " \u6d3b\u8dc3 / "\n              << (connections_.size() - active) << " \u7a7a\u95f2 / "\n              << connections_.size() << " \u603b\u8ba1" << std::endl;\n}\n\nsize_t ConnectionPool::poolSize() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    return connections_.size();\n}\n\nsize_t ConnectionPool::activeCount() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    return std::count_if(connections_.begin(), connections_.end(),\n        [](const auto& c) { return c->isInUse(); });\n}\n\n\n// ============================================================\n// \u6f14\u793a\u7a0b\u5e8f\n// ============================================================\nint main() {\n    std::cout << "========================================" << std::endl;\n    std::cout << "   Singleton \u6a21\u5f0f\u6f14\u793a" << std::endl;\n    std::cout << "========================================\\n" << std::endl;\n\n    // ---- 1. \u914d\u7f6e\u7ba1\u7406\u5668\u6f14\u793a ----\n    std::cout << "--- 1. \u5e94\u7528\u914d\u7f6e\u7ba1\u7406\u5668 (Meyers\' Singleton) ---\\n" << std::endl;\n\n    // \u9996\u6b21\u8bbf\u95ee\u65f6\u521d\u59cb\u5316\n    AppConfig& config1 = AppConfig::getInstance();\n    config1.loadFromDefaults();\n\n    // \u7b2c\u4e8c\u6b21\u83b7\u53d6\u7684\u662f\u540c\u4e00\u5b9e\u4f8b\n    AppConfig& config2 = AppConfig::getInstance();\n    config2.set("app.debug", "true");\n\n    // \u9a8c\u8bc1\u662f\u540c\u4e00\u4e2a\u5bf9\u8c61\n    std::cout << "\\n\u9a8c\u8bc1\u5355\u4f8b: config1 \u5730\u5740 = " << &config1\n              << ", config2 \u5730\u5740 = " << &config2 << std::endl;\n    std::cout << "\u662f\u5426\u4e3a\u540c\u4e00\u5b9e\u4f8b: " << (&config1 == &config2 ? "\u662f" : "\u5426") << std::endl;\n\n    // \u663e\u793a\u914d\u7f6e\n    std::cout << std::endl;\n    config1.printAll();\n\n    // ---- 2. \u591a\u7ebf\u7a0b\u5b89\u5168\u9a8c\u8bc1 ----\n    std::cout << "\\n--- 2. \u591a\u7ebf\u7a0b\u5b89\u5168\u9a8c\u8bc1 ---\\n" << std::endl;\n\n    std::vector<std::thread> threads;\n    std::mutex outputMutex;\n\n    // \u591a\u4e2a\u7ebf\u7a0b\u540c\u65f6\u83b7\u53d6\u5b9e\u4f8b\uff0c\u5e94\u8be5\u90fd\u5f97\u5230\u540c\u4e00\u4e2a\n    for (int i = 0; i < 4; ++i) {\n        threads.emplace_back([i, &outputMutex]() {\n            AppConfig& cfg = AppConfig::getInstance();\n            std::lock_guard<std::mutex> lock(outputMutex);\n            std::cout << "\u7ebf\u7a0b " << i << " \u83b7\u53d6\u5b9e\u4f8b\u5730\u5740: " << &cfg << std::endl;\n        });\n    }\n    for (auto& t : threads) {\n        t.join();\n    }\n    std::cout << "\u6240\u6709\u7ebf\u7a0b\u83b7\u53d6\u5230\u540c\u4e00\u5b9e\u4f8b -> \u7ebf\u7a0b\u5b89\u5168\u9a8c\u8bc1\u901a\u8fc7" << std::endl;\n\n    // ---- 3. \u6570\u636e\u5e93\u8fde\u63a5\u6c60\u6f14\u793a ----\n    std::cout << "\\n--- 3. \u6570\u636e\u5e93\u8fde\u63a5\u6c60 (Singleton + \u5bf9\u8c61\u6c60) ---\\n" << std::endl;\n\n    ConnectionPool& pool = ConnectionPool::getInstance();\n    pool.printStatus();\n\n    // \u83b7\u53d6\u51e0\u4e2a\u8fde\u63a5\u5e76\u6267\u884c SQL\n    std::cout << std::endl;\n    auto* conn1 = pool.acquire();\n    auto* conn2 = pool.acquire();\n    auto* conn3 = pool.acquire();\n\n    if (conn1) conn1->execute("SELECT * FROM users WHERE id = 1");\n    if (conn2) conn2->execute("INSERT INTO logs (msg) VALUES (\'login\')");\n    if (conn3) conn3->execute("UPDATE sessions SET active = true");\n\n    std::cout << std::endl;\n    pool.printStatus();\n\n    // \u5f52\u8fd8\u8fde\u63a5\n    std::cout << std::endl;\n    pool.release(conn1);\n    pool.release(conn2);\n    pool.printStatus();\n\n    // \u591a\u7ebf\u7a0b\u4f7f\u7528\u8fde\u63a5\u6c60\n    std::cout << "\\n--- 4. \u591a\u7ebf\u7a0b\u5e76\u53d1\u4f7f\u7528\u8fde\u63a5\u6c60 ---\\n" << std::endl;\n\n    pool.release(conn3);  // \u5148\u5168\u90e8\u5f52\u8fd8\n\n    std::vector<std::thread> workers;\n    for (int i = 0; i < 6; ++i) {\n        workers.emplace_back([i]() {\n            ConnectionPool& p = ConnectionPool::getInstance();\n            auto* c = p.acquire();\n            if (c) {\n                std::ostringstream ss;\n                ss << "SELECT * FROM table_" << i;\n                c->execute(ss.str());\n                // \u6a21\u62df\u5de5\u4f5c\n                std::this_thread::sleep_for(std::chrono::milliseconds(10));\n                p.release(c);\n            }\n        });\n    }\n    for (auto& w : workers) {\n        w.join();\n    }\n\n    std::cout << std::endl;\n    pool.printStatus();\n\n    std::cout << "\\n========================================" << std::endl;\n    std::cout << "\u5173\u952e\u70b9\u603b\u7ed3:" << std::endl;\n    std::cout << "1. Meyers\' Singleton \u5229\u7528 C++11 \u9759\u6001\u53d8\u91cf\u7ebf\u7a0b\u5b89\u5168\u4fdd\u8bc1" << std::endl;\n    std::cout << "2. \u5220\u9664\u62f7\u8d1d/\u79fb\u52a8\u6784\u9020\u548c\u8d4b\u503c\u8fd0\u7b97\u7b26\u9632\u6b62\u590d\u5236" << std::endl;\n    std::cout << "3. \u8fde\u63a5\u6c60\u5c55\u793a\u4e86 Singleton \u7684\u5178\u578b\u5e94\u7528\u573a\u666f" << std::endl;\n    std::cout << "4. \u591a\u7ebf\u7a0b\u73af\u5883\u4e0b\u7684\u6570\u636e\u5b89\u5168\u9700\u8981\u989d\u5916\u52a0\u9501\uff08mutex\uff09" << std::endl;\n    std::cout << "========================================" << std::endl;\n\n    return 0;\n}\n'})}),"\n",(0,s.jsx)(t.h2,{id:"\u6784\u5efa\u65b9\u5f0f",children:"\u6784\u5efa\u65b9\u5f0f"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cmake",metastring:'title="CMakeLists.txt"',children:"add_executable(Pattern_Singleton Singleton.cpp Singleton.h)\n"})}),"\n",(0,s.jsx)(t.admonition,{title:"\u7f16\u8bd1\u8fd0\u884c",type:"tip",children:(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-bash",children:"cd build\ncmake --build . --target Pattern_Singleton\n./Pattern_Singleton\n"})})})]})}function u(n={}){const{wrapper:t}={...(0,i.R)(),...n.components};return t?(0,s.jsx)(t,{...n,children:(0,s.jsx)(r,{...n})}):r(n)}},28453(n,t,e){e.d(t,{R:()=>c,x:()=>d});var o=e(96540);const s={},i=o.createContext(s);function c(n){const t=o.useContext(i);return o.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function d(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:c(n.components),o.createElement(i.Provider,{value:t},n.children)}}}]);